#include<stdio.h>
#define N 40

long long a[N][N];

long long solve( int n, int h )
{
  int i, o, p, j, k;
  if (a[n][h] >=0 ) return(a[n][h]);
  if (h>n)
  {
    a[n][h] = 0;
    return( a[n][h] );
  } 
  if (((n==1) && (h==1)) || ((n==0)&&(h==0)))
  {
    a[n][h] = 1;
    return( a[n][h] );
  } 

  if (h==0) 
  {
    a[n][h] = 0;
    return( a[n][h] );
  }

  a[n][h] = 0;
  for (i=0;i<=n-1;++i)
    for (j=0;j<=h-2;++j)
      a[n][h] += solve(i, h-1) * solve(n-i-1, j);
  a[n][h] *= 2;
  for (i=0;i<=n-1;++i)
    a[n][h] += solve(i, h-1) * solve(n-i-1, h-1);

  return( a[n][h] );
}         

